{"fully_compliant":{"type":"boolean","script":{"source":"boolean fully_compliant = true;
double latest_scan_date_age = -1;
double tenant_verification_date_age = -1;
boolean in_current_quarter = false;

// == Calculate _age fields == //
// you can't use runtime fields in runtime fields, so there is some minor code duplication here
// with in_current_quarter and inventory.tenant_verification_date_age.

// Guard for missing field
if (doc.containsKey('latest_scan_date') && doc['latest_scan_date'].size() > 0) {

    Instant now = Instant.ofEpochMilli(new Date().getTime());
    ZonedDateTime zNow = ZonedDateTime.ofInstant(now, ZoneId.of("UTC"));

    int month = zNow.getMonthValue();
    int year = zNow.getYear();

    // Determine fiscal quarter start
    int startMonth;

    if (month >= 10) {          // Oct–Dec → Q1
        startMonth = 10;
    } else if (month >= 7) {   // Jul–Sep → Q4
        startMonth = 7;
    } else if (month >= 4) {   // Apr–Jun → Q3
        startMonth = 4;
    } else {                   // Jan–Mar → Q2
        startMonth = 1;
    }

    // Start of the current fiscal quarter
    ZonedDateTime quarterStart = ZonedDateTime.of(
        year, startMonth, 1, 0, 0, 0, 0, ZoneId.of("UTC")
    );

    // Start of next quarter
    ZonedDateTime nextQuarterStart = quarterStart.plusMonths(3);

    ZonedDateTime fieldTime = doc['latest_scan_date'].value;

    // Check if within current fiscal quarter
    in_current_quarter = (!fieldTime.isBefore(quarterStart) && fieldTime.isBefore(nextQuarterStart));
}

if (doc['inventory.tenant_verification_date'].size() > 0 && doc['@timestamp'].size() > 0) {
  tenant_verification_date_age = ChronoUnit.DAYS.between(doc['inventory.tenant_verification_date'].value, doc['@timestamp'].value);
}

// == Check if the tenant has results, and is in scope for bod == //
if (
  doc['tenant.has_result'].size() <= 0 || doc['tenant.in_scope_for_bod'].size() <= 0 || 
  doc['tenant.has_result'].value != true || doc['tenant.in_scope_for_bod'].value != true
) {
  fully_compliant = false;
}

// == Check if the scan dates are within the acceptable range == //
if (!in_current_quarter) {
  fully_compliant = false;
}

if (tenant_verification_date_age > 365 || tenant_verification_date_age == -1) {
  fully_compliant = false;
}
